mapper.update:
UPDATE t_evaluation_run
SET status = #{status}, overall_score = #{overallScore}, metrics_json = #{metricsJson},
    finished_at = #{finishedAt}
WHERE id = #{id}

mapper.select:
SELECT * FROM t_evaluation_run
WHERE tenant_id = #{tenantId}
ORDER BY created_at DESC LIMIT #{size} OFFSET #{offset}

SELECT * FROM t_evaluation_run
WHERE dataset_id = #{datasetId}
ORDER BY created_at DESC LIMIT #{size} OFFSET #{offset}
